};

import React, { useEffect, useState } from "react";
import api from "../services/api";
import { useNavigate } from "react-router-dom";
import "./OrdersPage.css";


const STATUS_COLORS = {
  Delivered: { bg: "rgba(74,180,100,0.12)", text: "#5ecb78", border: "rgba(74,180,100,0.25)" },
  "In Transit": { bg: "rgba(247,165,75,0.12)", text: "#f7a54b", border: "rgba(247,165,75,0.3)" },
  Processing: { bg: "rgba(100,140,240,0.12)", text: "#8aabff", border: "rgba(100,140,240,0.25)" },
  Cancelled: { bg: "rgba(220,80,80,0.1)", text: "#e07070", border: "rgba(220,80,80,0.2)" },
};

function StatusBadge({ status }) {
  const c = STATUS_COLORS[status] || STATUS_COLORS["Processing"];
  return (
    <span
      className="status-badge"
      style={{ background: c.bg, color: c.text, border: `1px solid ${c.border}` }}
    >
      {status}
    </span>
  );
}

function OrderCard({ order }) {
  const [expanded, setExpanded] = useState(false);

  return (
    <div className={`order-card ${expanded ? "expanded" : ""}`}>
      <button className="order-card-header" onClick={() => setExpanded(p => !p)}>
        <div className="order-meta">
          <span className="order-id">{order.id}</span>
          <span className="order-date">{order.date}</span>
        </div>
        <div className="order-right">
          <StatusBadge status={order.status} />
          <span className="order-total">{order.total}</span>
          <svg
            className={`order-chevron ${expanded ? "open" : ""}`}
            width="14" height="14" viewBox="0 0 12 12" fill="none"
          >
            <path d="M2 4L6 8L10 4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
        </div>
      </button>

      {expanded && (
        <div className="order-items">
          <div className="order-items-divider" />
          {order.items.map((item, i) => (
            <div className="order-item-row" key={i}>
              <div className="order-item-thumb">
                {item.img
                  ? <img src={item.img} alt={item.name} />
                  : <span className="thumb-placeholder">☽</span>
                }
              </div>
              <div className="order-item-info">
                <span className="item-name">{item.name}</span>
                <span className="item-qty">Qty: {item.qty}</span>
              </div>
              <span className="item-price">{item.price}</span>
            </div>
          ))}
          <div className="order-actions">
            <button className="btn-ghost">Track Order</button>
            <button className="btn-ghost">Buy Again</button>
          </div>
        </div>
      )}
    </div>
  );
}

export default function OrdersPage() {
  const navigate = useNavigate();
  const [filter, setFilter] = useState("All");
  const filters = ["All", "Delivered", "In Transit", "Processing"];

  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    let alive = true;
    (async () => {
      try {
        setLoading(true);
        setError(null);

        const res = await api.get("/api/user/orders/");
        const data = res?.data;

        const list = Array.isArray(data)
          ? data
          : Array.isArray(data?.orders)
            ? data.orders
            : [];

        if (!alive) return;
        setOrders(list);
      } catch (e) {
        if (!alive) return;
        setError(e?.response?.data?.message || e?.message || "Failed to load orders");
      } finally {
        if (!alive) return;
        setLoading(false);
      }
    })();
    return () => {
      alive = false;
    };
  }, []);

  const visible = filter === "All" ? orders : orders.filter((o) => o.status === filter);

  return (
    <div className="page-shell">
      <div className="page-container">

        <button className="back-btn" onClick={() => navigate(-1)}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
            <path d="M19 12H5M5 12L12 19M5 12L12 5" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
          Back
        </button>

        <div className="page-header">
          <h1 className="page-title">My Orders</h1>
          <p className="page-subtitle">Track and manage your purchases</p>
        </div>

        {/* Filter pills */}
        <div className="filter-pills">
          {filters.map(f => (
            <button
              key={f}
              className={`filter-pill ${filter === f ? "active" : ""}`}
              onClick={() => setFilter(f)}
            >
              {f}
            </button>
          ))}
        </div>

        {/* Orders list */}
        <div className="orders-list">
          {loading ? (
            <div className="empty-state">
              <span className="empty-icon">⏳</span>
              <p>Loading orders…</p>
            </div>
          ) : error ? (
            <div className="empty-state">
              <span className="empty-icon">⚠️</span>
              <p>{error}</p>
            </div>
          ) : visible.length === 0 ? (
            <div className="empty-state">
              <span className="empty-icon">📦</span>
              <p>No orders found</p>
            </div>
          ) : (
            visible.map((order) => <OrderCard key={order.id || order.order_id} order={order} />)
          )}
        </div>

      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Line, Bar, Doughnut } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
  Filler,
} from 'chart.js';
import {
  getAnalytics,
  getOrders,
  updateSystemSettings,
  updateUserRole,
  getUsers,
} from '../services/api';
import './admin.css';


ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
  Filler
);

const AdminDashboard = () => {
  const navigate = useNavigate();
  const [users, setUsers] = useState([]);
  const [updatingUserIds, setUpdatingUserIds] = useState({});

  const fetchUsers = async () => {
    const data = await getUsers();
    setUsers(Array.isArray(data) ? data : data?.users || []);
  };

  useEffect(() => {
    fetchUsers().catch((e) => console.error('Error fetching users:', e));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const onPromoteDemote = async (userId, targetRole) => {
    setUpdatingUserIds((prev) => ({ ...prev, [userId]: true }));
    try {
      const res = await updateUserRole(userId, targetRole);
      await fetchUsers();

      if (res?.requires_relogin) {
        // Existing JWT for that user still contains the old role.
        // They must log out + log back in for the new token claims to take effect.
        window.dispatchEvent(
          new CustomEvent('sonner:toast', {
            detail: {
              title: 'Role updated',
              description: 'User must log out and log back in for the change to take effect.',
              type: 'info',
            },
          })
        );
      }
    } catch (e) {
      console.error('Error updating user role:', e);
    } finally {
      setUpdatingUserIds((prev) => ({ ...prev, [userId]: false }));
    }
  };
  const [stats, setStats] = useState({
    totalSales: 0,
    totalOrders: 0,
    totalUsers: 0,
    totalProducts: 0,
    pendingOrders: 0,
    lowStock: 0,
    revenueGrowth: 0,
    orderGrowth: 0,
  });
  
  const [recentOrders, setRecentOrders] = useState([]);
  const [topProducts, setTopProducts] = useState([]);
  const [salesData, setSalesData] = useState({});
  const [maintenanceMode, setMaintenanceMode] = useState(false);
  const [loading, setLoading] = useState(true);

  const applyDashboardData = (analytics, orders) => {
    setStats({
      totalSales: analytics.total_sales || 0,
      totalOrders: analytics.total_orders || 0,
      totalUsers: analytics.total_users || 0,
      totalProducts: analytics.total_products || 0,
      pendingOrders: analytics.pending_orders || 0,
      lowStock: analytics.low_stock || 0,
      revenueGrowth: analytics.revenue_growth || 0,
      orderGrowth: analytics.order_growth || 0,
    });
    const items = orders?.items || [];
    setRecentOrders(items);
    setTopProducts(analytics.top_products || []);
    setSalesData(analytics.sales_by_day || {});
    setMaintenanceMode(analytics.maintenance_mode || false);
    setLoading(false);
  };

  const normalizeOrderRow = (order) => {
    const id = order?.id ?? order?._id ?? order?.order_id ?? '';


    const customer_name =
      order?.customer_name ??
      order?.customer?.name ??
      order?.customer?.full_name ??
      order?.user?.email ??
      'Unknown';

    const rawTotal =
      order?.total_amount ??
      order?.total ??
      order?.totalAmount ??
      order?.amount_total ??
      order?.amount ??
      0;

    const totalNumber =
      typeof rawTotal === 'number'
        ? rawTotal
        : typeof rawTotal === 'string'
          ? Number(rawTotal)
          : 0;

    const total_display =
      typeof rawTotal === 'string' && rawTotal.includes('$')
        ? rawTotal
        : `$${(Number.isFinite(totalNumber) ? totalNumber : 0).toFixed(2)}`;

    const rawStatus = (order?.status ?? order?.order_status ?? '').toString();

    const status_label =
      rawStatus
        .replace(/_/g, ' ')
        .trim()
        .replace(/\b\w/g, (m) => m.toUpperCase()) || 'Unknown';

    const status_badge_key = rawStatus
      .replace(/\s+/g, '-')
      .replace(/_/g, '-')
      .toLowerCase();

    return {
      id,
      customer_name,
      total_display,
      status_label,
      status_badge_key,
    };
  };

  useEffect(() => {
    let cancelled = false;
    const load = async () => {
      try {
        const [analytics, orders] = await Promise.all([
          getAnalytics(),
          getOrders({ limit: 10 }),
        ]);

        if (!cancelled) applyDashboardData(analytics, orders);
      } catch (error) {
        console.error('Error fetching dashboard data:', error);
        if (!cancelled) setLoading(false);
      }
    };
    load();
    return () => { cancelled = true; };
  }, []);

  const fetchDashboardData = async () => {
    try {
      const [analytics, orders] = await Promise.all([
        getAnalytics(),
        getOrders({ limit: 10 }),
      ]);

      applyDashboardData(analytics, orders);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    }
  };

  const toggleMaintenance = async () => {
    try {
      await updateSystemSettings({ maintenance_mode: !maintenanceMode });
      setMaintenanceMode(!maintenanceMode);
    } catch (error) {
      console.error('Error toggling maintenance mode:', error);
    }

  };

  const salesChartData = {
    labels: salesData.labels || ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
    datasets: [
      {
        label: 'Sales ($)',
        data: salesData.values || [0, 0, 0, 0, 0, 0, 0],
        borderColor: '#2a5298',
        backgroundColor: 'rgba(42, 82, 152, 0.1)',
        tension: 0.4,
        fill: true,
      },
    ],
  };

  const topProductsData = {
    labels: topProducts.map(p => p.name),
    datasets: [
      {
        label: 'Units Sold',
        data: topProducts.map(p => p.units_sold),
        backgroundColor: '#2a5298',
      },
    ],
  };

  const orderStatusData = {
    labels: ['Pending', 'Paid', 'Shipped', 'Delivered', 'Cancelled'],
    datasets: [
      {
        data: [
          stats.pendingOrders,
          stats.totalOrders * 0.3,
          stats.totalOrders * 0.2,
          stats.totalOrders * 0.4,
          stats.totalOrders * 0.1,
        ],
        backgroundColor: ['#ffc107', '#17a2b8', '#007bff', '#28a745', '#dc3545'],
      },
    ],
  };

  if (loading) {
    return <div className="admin-container">Loading dashboard...</div>;
  }

  return (
    <div className="admin-main">
      <div className="admin-header">
        <h1>Dashboard Overview</h1>
        <div className="admin-header-actions">
          <button
            className="btn btn-ghost"
            onClick={() => navigate('/profile')}
            aria-label="Go to user dashboard"
          >
            View User Dashboard
          </button>
          <button className="btn btn-primary" onClick={fetchDashboardData}>
            Refresh Data
          </button>
        </div>
      </div>

      {maintenanceMode && (
        <div className="maintenance-mode">
          <span>⚠️ Maintenance mode is currently ACTIVE. Website is in read-only mode.</span>
          <button className="btn btn-danger" onClick={toggleMaintenance}>
            Disable Maintenance
          </button>
        </div>
      )}

      {/* TOP METRICS */}
      <div className="top-stats-grid">
        <div className="stat-card large-card">
          <div className="stat-title">Revenue Overview</div>

          <div className="big-stat">
            ${stats.totalSales.toLocaleString()}
          </div>

          <div className="stat-change">
            ↑ {stats.revenueGrowth}% this month
          </div>

          <div className="chart-wrapper">
            <Line data={salesChartData} options={{ responsive: true }} />
          </div>
        </div>

        <div className="side-column">
          <div className="stat-card">
            <div className="stat-title">Orders</div>
            <div className="stat-value">
              {stats.totalOrders}
            </div>

            <div className="stat-change">
              ↑ {stats.orderGrowth}% growth
            </div>
          </div>

          <div className="stat-card">
            <div className="stat-title">Order Distribution</div>

            <div className="small-chart">
              <Doughnut
                data={orderStatusData}
                options={{ responsive: true }}
              />
            </div>
          </div>
        </div>
      </div>

      {/* MINI CARDS */}
      <div className="mini-stats-grid">
        <div className="stat-card">
          <div className="stat-title">Users</div>
          <div className="stat-value">
            {stats.totalUsers}
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-title">Products</div>
          <div className="stat-value">
            {stats.totalProducts}
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-title">Pending Orders</div>
          <div className="stat-value">
            {stats.pendingOrders}
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-title">Avg Order Value</div>
          <div className="stat-value">
            ${(stats.totalSales / stats.totalOrders || 0).toFixed(2)}
          </div>
        </div>
      </div>

      {/* ADMIN USERS ROLE MANAGEMENT */}
      <div className="bottom-grid">
        <AdminUsersSection
          users={users}
          onPromoteDemote={onPromoteDemote}
          updatingUserIds={updatingUserIds}
        />
      </div>

      {/* LOWER SECTION */}
      <div className="bottom-grid">
        {/* RECENT ORDERS */}
        <div className="stat-card orders-card">
          <div className="section-header">Recent Orders</div>

          <div className="data-table">
            <table>
              <thead>
                <tr>
                  <th>Order</th>
                  <th>Customer</th>
                  <th>Amount</th>
                  <th>Status</th>
                </tr>
              </thead>

              <tbody>
                {recentOrders.map((order) => {
                  const normalized = normalizeOrderRow(order);
                  return (
                    <tr key={normalized.id}>
                      <td>#{String(normalized.id).slice(0, 8)}</td>
                      <td>{normalized.customer_name}</td>
                      <td>{normalized.total_display}</td>
                      <td>
                        <span
                          className={`status-badge status-${normalized.status_badge_key}`}
                        >
                          {normalized.status_label}
                        </span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>

        {/* TOP PRODUCTS */}
        <div className="stat-card products-card">
          <div className="section-header">Top Products</div>

          <Bar
            data={topProductsData}
            options={{ responsive: true }}
          />
        </div>
      </div>
    </div>
  );
};

